use PDF::API2;
use File::Slurp;

sub extract_info {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $pages = $pdf->pages;

    for (1 .. $pages) {
        my $page = $pdf->page($_);
        my $content = $page->content;
        if ($content =~ /Author:\s*(.*?)\n/) {
            print "Auteur : $1\n";
        }
        if ($content =~ /CreationDate:\s*(.*?)\n/) {
            print "Date de création : $1\n";
        }
        if ($content =~ /ModDate:\s*(.*?)\n/) {
            print "Date de modification : $1\n";
        }
        if ($content =~ /(\d{1,2}\s+\w+\s+\d{4}\s+\d{1,2}:\d{2}:\d{2})/) {
            print "Date et heure : $1\n";
        }
    }
}

# Utilisation
my $pdf_file = 'path_to_your_pdf_file.pdf';
extract_info($pdf_file);
